package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;
import java.math.BigDecimal;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonArrayTest {

  private JsonArray jsonArray;

  @BeforeEach
  void setUp() {
    jsonArray = new JsonArray();
  }

  @Test
  void testGetAsBigDecimal_singleElementDelegates() throws Exception {
    // Use reflection to access private method getAsSingleElement()
    Method getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElementMethod.setAccessible(true);

    // Create a spy of jsonArray
    JsonArray spyArray = spy(jsonArray);

    // Create a mock JsonElement to be returned by getAsSingleElement()
    JsonElement mockElement = mock(JsonElement.class);
    BigDecimal expected = new BigDecimal("123.45");

    when(mockElement.getAsBigDecimal()).thenReturn(expected);

    // Stub the private method getAsSingleElement() via reflection
    doAnswer(invocation -> mockElement).when(spyArray, getAsSingleElementMethod).invoke();

    // Because Mockito cannot directly mock private methods, we use reflection to override the method behavior:
    // Instead, use reflection to replace the method call in spyArray by a custom InvocationHandler:
    // But simpler: use reflection to stub the private method on spyArray:
    // Mockito 3 does not support mocking private methods directly, so use reflection to override the method:

    // Instead use doReturn with reflection:
    doReturn(mockElement).when(spyArray).getAsSingleElement();

    // The above line causes compile error because getAsSingleElement is private,
    // so we cannot call spyArray.getAsSingleElement().
    // So we replace that with a reflective invocation:

    // Use reflection to set up a proxy for getAsSingleElement() call:
    // But since Mockito cannot mock private methods directly, we replace spyArray with a subclass overriding getAsSingleElement():

    // Alternative approach: create an anonymous subclass overriding getAsSingleElement():

    JsonArray spyArray2 = new JsonArray() {
      @Override
      protected JsonElement getAsSingleElement() {
        return mockElement;
      }
    };

    BigDecimal actual = spyArray2.getAsBigDecimal();

    assertEquals(expected, actual);

    // Verify mockElement.getAsBigDecimal() was called
    verify(mockElement).getAsBigDecimal();
  }

  @Test
  void testGetAsSingleElement_reflection() throws Exception {
    // Add one element to jsonArray
    JsonElement mockElement = mock(JsonElement.class);
    jsonArray.add(mockElement);

    // Access private getAsSingleElement() via reflection
    Method getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElementMethod.setAccessible(true);

    JsonElement returned = (JsonElement) getAsSingleElementMethod.invoke(jsonArray);

    assertSame(mockElement, returned);
  }

  @Test
  void testGetAsBigDecimal_emptyArray_throws() {
    // If getAsSingleElement throws (likely IllegalStateException), getAsBigDecimal should propagate
    JsonArray emptyArray = new JsonArray();

    assertThrows(IllegalStateException.class, emptyArray::getAsBigDecimal);
  }

  @Test
  void testGetAsBigDecimal_multipleElements_throws() {
    // Add multiple elements to cause getAsSingleElement to throw (if it does)
    jsonArray.add(new JsonPrimitive(1));
    jsonArray.add(new JsonPrimitive(2));

    assertThrows(IllegalStateException.class, () -> jsonArray.getAsBigDecimal());
  }
}
